#!/bin/bash
# slurm-install.sh — Full Slurm build + install from source on CentOS/RHEL DMR systems
# Usage: bash slurm-install.sh [--prefix /usr/local/slurm] [--skip-build]
# Tested on: CentOS Stream 10, kernel 6.18.0-dmr.bkc, Slurm 26.05.0-0rc1
set -euo pipefail

# --- Config ---
PREFIX=${PREFIX:-/usr/local/slurm}
SYSCONFDIR=${SYSCONFDIR:-/etc/slurm}
SLURM_SRC=${SLURM_SRC:-/root/slurm}
SLURM_STATE=/var/lib/slurm
SLURM_SPOOL=/tmp/slurmd
SLURM_LOGS=/var/log/slurm

# Parse flags
while [[ $# -gt 0 ]]; do
  case $1 in
    --prefix) PREFIX="$2"; shift 2 ;;
    --skip-build) SKIP_BUILD=1; shift ;;
    *) echo "Unknown arg: $1"; exit 1 ;;
  esac
done

log() { echo "[$(date '+%H:%M:%S')] $*"; }
die() { echo "ERROR: $*" >&2; exit 1; }

# --- 1. Dependencies ---
log "Installing build dependencies..."
dnf install -y \
    gcc make autoconf automake libtool \
    munge munge-libs munge-devel \
    pam-devel readline-devel hwloc-devel mariadb-devel \
    2>&1 | grep -E "Installed|already|Error" || true

# --- 2. slurm user ---
log "Creating slurm system user..."
id slurm &>/dev/null || useradd -r -U -d /var/lib/slurm -s /bin/false slurm
id slurm

# --- 3. MUNGE ---
log "Setting up MUNGE authentication..."
# Generate key if missing
[ -f /etc/munge/munge.key ] || /usr/sbin/mungekey
# Fix ownership (munge daemon requires files owned by munge user)
chown -R munge:munge /var/log/munge /var/lib/munge /etc/munge
chmod 755 /var/log/munge /var/lib/munge
chmod 600 /etc/munge/munge.key
systemctl start munge
systemctl enable munge
systemctl is-active munge && log "MUNGE running ✓" || die "MUNGE failed to start"

# --- 4. Clone Slurm ---
if [ ! -d "$SLURM_SRC" ]; then
  log "Cloning Slurm from GitHub..."
  git clone https://github.com/SchedMD/slurm.git "$SLURM_SRC"
else
  log "Slurm source already present at $SLURM_SRC"
fi

# --- 5. Build ---
if [ "${SKIP_BUILD:-0}" != "1" ]; then
  log "Configuring Slurm (prefix=$PREFIX sysconfdir=$SYSCONFDIR)..."
  cd "$SLURM_SRC"
  ./configure --prefix="$PREFIX" --sysconfdir="$SYSCONFDIR" \
              --with-munge=/usr 2>&1 | tail -3

  log "Building (make -j4, ~2 min)..."
  make -j4 2>&1 | grep -E "error:|warning:|Entering|Leaving" | tail -20

  log "Installing..."
  make install 2>&1 | tail -5

  # Register libs
  ldconfig -n "${PREFIX}/lib"
  log "Build complete ✓"
fi

# Verify install
"${PREFIX}/bin/sinfo" --version || die "sinfo not found after install"
log "Slurm binary: $("${PREFIX}/bin/sinfo" --version)"

# --- 6. Directories ---
log "Creating runtime directories..."
mkdir -p "$SLURM_STATE" "$SLURM_SPOOL" "$SLURM_LOGS" "$SYSCONFDIR"
chown -R slurm:slurm "$SLURM_STATE" "$SLURM_LOGS" "$SYSCONFDIR"
chmod 755 "$SLURM_STATE" "$SLURM_LOGS"

# --- 7. cgroup.conf ---
log "Writing cgroup.conf..."
cat > "$SYSCONFDIR/cgroup.conf" << 'EOF'
# cgroup/v1 — v2 not mounted on DMR BKC kernel
# Constraints disabled; proctrack handled by linuxproc plugin instead
CgroupPlugin=cgroup/v1
ConstrainCores=no
ConstrainDevices=no
ConstrainRAMSpace=no
ConstrainSwapSpace=no
EOF

# --- 8. slurm.conf (auto-detect system) ---
NODE_IP=$(ip addr show | awk '/inet / && !/127\.0\.0\.1/{print $2}' | cut -d/ -f1 | head -1)
NODE_NAME=$(hostname -s)
NODE_CPUS=$(nproc)
NODE_MEM=$(( $(free -m | awk '/Mem:/{print $2}') - 600 ))

log "Detected: node=$NODE_NAME ip=$NODE_IP cpus=$NODE_CPUS mem=${NODE_MEM}MB"

cat > "$SYSCONFDIR/slurm.conf" << EOF
# Slurm — Single-Node DMR Configuration
# Generated by slurm-install.sh on $(date)

ClusterName=dmr-testbed
SlurmctldHost=${NODE_NAME}(${NODE_IP})
SlurmUser=slurm
SlurmctldPort=6817
SlurmdPort=6818
AuthType=auth/munge
StateSaveLocation=${SLURM_STATE}
SlurmdSpoolDir=${SLURM_SPOOL}

SchedulerType=sched/backfill
SelectType=select/linear
TaskPlugin=task/none
JobAcctGatherType=jobacct_gather/none
ProctrackType=proctrack/linuxproc

# Node: NodeAddr uses LAN IP to avoid external DNS failures
NodeName=${NODE_NAME} NodeAddr=${NODE_IP} CPUs=${NODE_CPUS} \\
    Sockets=1 CoresPerSocket=${NODE_CPUS} ThreadsPerCore=1 \\
    RealMemory=${NODE_MEM}

# 4 partitions sharing one physical node — enables scheduling simulation
PartitionName=batch Nodes=${NODE_NAME} MaxTime=UNLIMITED  Priority=1 Default=YES
PartitionName=debug Nodes=${NODE_NAME} MaxTime=00:30:00   Priority=2
PartitionName=fast  Nodes=${NODE_NAME} MaxTime=00:10:00   Priority=3
PartitionName=long  Nodes=${NODE_NAME} MaxTime=7-00:00:00 Priority=0

PriorityType=priority/basic
EOF

log "slurm.conf written ✓"

# --- 9. Systemd services ---
log "Writing systemd service files..."
cat > /etc/systemd/system/slurmctld.service << SVCEOF
[Unit]
Description=Slurm controller daemon
After=network.target munge.service
Wants=munge.service
ConditionPathExists=/etc/slurm/slurm.conf

[Service]
Type=forking
ExecStart=${PREFIX}/sbin/slurmctld
ExecReload=/bin/kill -HUP \$MAINPID
LimitNOFILE=infinity
LimitMEMLOCK=infinity
Restart=on-failure
RestartSec=30s

[Install]
WantedBy=multi-user.target
SVCEOF

cat > /etc/systemd/system/slurmd.service << SVCEOF
[Unit]
Description=Slurm node daemon
After=network.target munge.service
Wants=munge.service
ConditionPathExists=/etc/slurm/slurm.conf

[Service]
Type=forking
ExecStart=${PREFIX}/sbin/slurmd
ExecReload=/bin/kill -HUP \$MAINPID
LimitNOFILE=infinity
LimitMEMLOCK=infinity
LimitSTACK=infinity
Restart=on-failure
RestartSec=30s

[Install]
WantedBy=multi-user.target
SVCEOF

systemctl daemon-reload
systemctl enable slurmctld slurmd

# --- 10. PATH ---
grep -q "local/slurm/bin" ~/.bashrc || \
    echo 'export PATH="/usr/local/slurm/bin:/usr/local/slurm/sbin:$PATH"' >> ~/.bashrc

# --- 11. Start ---
log "Starting Slurm daemons..."
rm -f "$SLURM_STATE"/*   # clear any stale state

"${PREFIX}/sbin/slurmctld"
sleep 1
"${PREFIX}/sbin/slurmd"
sleep 3

# --- Verify ---
log ""
log "=== Cluster Status ==="
"${PREFIX}/bin/sinfo" --long || die "sinfo failed — check journalctl -xeu slurmctld"

log ""
log "Install complete. Path has been added to ~/.bashrc"
log "Run 'source ~/.bashrc' or start a new shell, then use: sinfo, sbatch, squeue"
